A `rewrites()` or `redirects()` rule that builds its external destination hostname from request-controlled input can be pointed at an arbitrary hostname, regardless of the rule's hostname suffix. For a rewrite, Next.js proxies the request to that arbitrary host and serves the response from the application's origin, leading to Server-Side Request forgery. A `redirects()` rule configured this way is vulnerable to an Open Redirect.

This affects any destination that puts a dynamic segment in the hostname, whether from the path:

```javascript
// next.config.js
module.exports = {
  async rewrites() {
    return [
      {
        source: '/:tenant',
        destination: 'https://:tenant.api.example.com',
      },
    ]
  },
}
```

or from a `has` capture:

```javascript
// next.config.js
module.exports = {
  async rewrites() {
    return [
      {
        source: '/',
        has: [{ type: 'query', key: 'region', value: '(?<region>.+)' }],
        destination: 'https://:region.api.example.com',
      },
    ]
  },
}
```

## Workarounds

If you cannot upgrade immediately, do not build the hostname of an external `rewrites()` or `redirects()` destination from user-controlled input. If a dynamic subdomain is required, constrain the value to hostname-safe characters:  `value: '(?<region>[a-z0-9-]+)'`.", "ghsa_id": "GHSA-p9j2-gv94-2wf4", "github_reviewed_at": "2026-07-22T23:02:23Z", "html_url": "https://github.com/advisories/GHSA-p9j2-gv94-2wf4", "identifiers": [{"type": "GHSA", "value": "GHSA-p9j2-gv94-2wf4"}, {"type": "CVE", "value": "CVE-2026-64645"}], "nvd_published_at": null, "published_at": "2026-07-22T23:02:23Z", "references": ["https://github.com/vercel/next.js/security/advisories/GHSA-p9j2-gv94-2wf4", "https://github.com/vercel/next.js/commit/35f501357e9b0fe7c950b0d6aa8fcf5343f707e9", "https://github.com/vercel/next.js/commit/d3033266c6dff23f7be71e19341fe3a8c6e2c599", "https://github.com/vercel/next.js/releases/tag/v15.5.21", "https://github.com/vercel/next.js/releases/tag/v16.2.11", "https://github.com/advisories/GHSA-p9j2-gv94-2wf4"], "repository_advisory_url": "https://api.github.com/repos/vercel/next.js/security-advisories/GHSA-p9j2-gv94-2wf4", "severity": "high", "source_code_location": "https://github.com/vercel/next.js", "summary": "Next.js: Server-Side Request Forgery in rewrites via attacker-controlled destination hostname", "type": "reviewed", "updated_at": "2026-07-22T23:02:25Z", "url": "https://api.github.com/advisories/GHSA-p9j2-gv94-2wf4", "vulnerabilities": [{"first_patched_version": "15.5.21", "package": {"ecosystem": "npm", "name": "next"}, "vulnerable_functions": [], "vulnerable_version_range": ">= 12.0.0, < 15.5.21"}, {"first_patched_version": "16.2.11", "package": {"ecosystem": "npm", "name": "next"}, "vulnerable_functions": [], "vulnerable_version_range": ">= 16.0.0, < 16.2.11"}], "withdrawn_at": null}
